const SKILLS_KEY = "nexus_skills_v2";
const ACTIVE_SKILLS_KEY = "nexus_active_skills";
const SKILL_RATINGS_KEY = "nexus_skill_ratings";

export async function loadSkills(): Promise<Skill[]> {
  const data = await AsyncStorage.getItem(SKILLS_KEY);
  if (!data) return DEFAULT_SKILLS.map((s) => ({ ...s }));
  const saved = JSON.parse(data) as Skill[];
  const savedIds = new Set(saved.map((s) => s.id));
  return [...saved, ...DEFAULT_SKILLS.filter((s) => !savedIds.has(s.id))];
}

export async function saveSkills(skills: Skill[]): Promise<void> {
  await AsyncStorage.setItem(SKILLS_KEY, JSON.stringify(skills));
}

export async function getActiveSkills(username: string): Promise<Skill[]> {
  const data = await AsyncStorage.getItem(`${ACTIVE_SKILLS_KEY}_${username}`);
  if (!data) return [];
  return JSON.parse(data);
}

export async function setActiveSkills(username: string, skills: Skill[]): Promise<void> {
  await AsyncStorage.setItem(`${ACTIVE_SKILLS_KEY}_${username}`, JSON.stringify(skills.slice(0, 3)));
}

// Legacy compat
export async function getActiveSkill(username: string): Promise<Skill | null> {
  const skills = await getActiveSkills(username);
  return skills[0] || null;
}

export async function setActiveSkill(username: string, skill: Skill | null): Promise<void> {
  if (!skill) {
    await setActiveSkills(username, []);
  } else {
    const current = await getActiveSkills(username);
    const filtered = current.filter((s) => s.id !== skill.id);
    await setActiveSkills(username, [skill, ...filtered]);
  }
}

export async function saveSkillRating(username: string, skillId: string, rating: number): Promise<void> {
  const key = `${SKILL_RATINGS_KEY}_${username}`;
  const data = await AsyncStorage.getItem(key);
  const ratings: Record<string, number> = data ? JSON.parse(data) : {};
  ratings[skillId] = rating;
  await AsyncStorage.setItem(key, JSON.stringify(ratings));
}

export async function getSkillRatings(username: string): Promise<Record<string, number>> {
  const key = `${SKILL_RATINGS_KEY}_${username}`;
  const data = await AsyncStorage.getItem(key);
  return data ? JSON.parse(data) : {};
}

export function suggestSkillForMessage(message: string, skills: Skill[]): Skill | null {
  const words = message.toLowerCase().split(/\s+/);
  let bestMatch: Skill | null = null;
  let bestScore = 0;
  for (const skill of skills) {
    if (!skill.isInstalled) continue;
    let score = 0;
    for (const kw of skill.keywords) {
      if (words.some((w) => w.includes(kw) || kw.includes(w))) score++;
    }
    if (score > bestScore) {
      bestScore = score;
      bestMatch = skill;
    }
  }
  return bestScore >= 2 ? bestMatch : null;
}
